INSERT INTO sentences (category_id, text_tr, text_en, text_sv, text_de, keywords_tr, keywords_en, keywords_sv, keywords_de, difficulty, is_free, sort_order) VALUES
(1, 'Hava yağmurlu olduğu için dışarı çıkmadım.', 'I didn''t go out because it was raining.', 'Jag gick inte ut eftersom det regnade.', 'Ich bin nicht rausgegangen, weil es regnete.', '["çıkmadım", "go out", "gick inte ut", "rausgegangen"]', '["go out", "go out", "gick inte ut", "rausgegangen"]', '["gick inte ut", "go out", "gick inte ut", "rausgegangen"]', '["rausgegangen", "go out", "gick inte ut", "rausgegangen"]', 'intermediate', true, 11),
(1, 'Yemek yedikten sonra film izleyeceğim.', 'After eating, I''ll watch a movie.', 'Efter att ha ätit kommer jag att se en film.', 'Nach dem Essen werde ich einen Film schauen.', '["yemek yedikten sonra", "after eating", "efter att ha ätit", "nach dem essen"]', '["after eating", "after eating", "efter att ha ätit", "nach dem essen"]', '["efter att ha ätit", "after eating", "efter att ha ätit", "nach dem essen"]', '["nach dem essen", "after eating", "efter att ha ätit", "nach dem essen"]', 'intermediate', true, 12),
(1, 'Arkadaşımı gördüğümde çok mutlu oldum.', 'I was very happy when I saw my friend.', 'Jag blev mycket glad när jag såg min vän.', 'Ich war sehr glücklich, als ich meinen Freund sah.', '["çok mutlu oldum", "very happy", "mycket glad", "sehr glücklich"]', '["very happy", "very happy", "mycket glad", "sehr glücklich"]', '["mycket glad", "very happy", "mycket glad", "sehr glücklich"]', '["sehr glücklich", "very happy", "mycket glad", "sehr glücklich"]', 'intermediate', true, 13),
(1, 'Kitap okumayı seviyorum çünkü rahatlatıcı.', 'I like reading books because it''s relaxing.', 'Jag gillar att läsa böcker eftersom det är avslappnande.', 'Ich mag Bücher lesen, weil es entspannend ist.', '["rahatlatıcı", "relaxing", "avslappnande", "entspannend"]', '["relaxing", "relaxing", "avslappnande", "entspannend"]', '["avslappnande", "relaxing", "avslappnande", "entspannend"]', '["entspannend", "relaxing", "avslappnande", "entspannend"]', 'intermediate', true, 14),
(1, 'Pazara gidip sebze alacağım.', 'I''ll go to the market and buy vegetables.', 'Jag ska gå till marknaden och köpa grönsaker.', 'Ich werde zum Markt gehen und Gemüse kaufen.', '["sebze alacağım", "buy vegetables", "köpa grönsaker", "gemüse kaufen"]', '["buy vegetables", "buy vegetables", "köpa grönsaker", "gemüse kaufen"]', '["köpa grönsaker", "buy vegetables", "köpa grönsaker", "gemüse kaufen"]', '["gemüse kaufen", "buy vegetables", "köpa grönsaker", "gemüse kaufen"]', 'intermediate', true, 15),
(1, 'Telefonum şarj olduğu için konuşabiliriz.', 'We can talk because my phone is charged.', 'Vi kan prata eftersom min telefon är laddad.', 'Wir können reden, weil mein Telefon geladen ist.', '["şarj olduğu için", "charged", "laddad", "geladen"]', '["charged", "charged", "laddad", "geladen"]', '["laddad", "charged", "laddad", "geladen"]', '["geladen", "charged", "laddad", "geladen"]', 'intermediate', true, 16),
(1, 'Hava soğuk olduğu halde yürüyüş yaptım.', 'I went for a walk although it was cold.', 'Jag gick en promenad trots att det var kallt.', 'Ich bin spazieren gegangen, obwohl es kalt war.', '["yürüyüş yaptım", "went for a walk", "gick en promenad", "spazieren gegangen"]', '["went for a walk", "went for a walk", "gick en promenad", "spazieren gegangen"]', '["gick en promenad", "went for a walk", "gick en promenad", "spazieren gegangen"]', '["spazieren gegangen", "went for a walk", "gick en promenad", "spazieren gegangen"]', 'intermediate', true, 17),
(1, 'Kahve içmeden güne başlayamam.', 'I can''t start the day without drinking coffee.', 'Jag kan inte börja dagen utan att dricka kaffe.', 'Ich kann den Tag nicht beginnen, ohne Kaffee zu trinken.', '["kahve içmeden", "drinking coffee", "dricka kaffe", "kaffee zu trinken"]', '["drinking coffee", "drinking coffee", "dricka kaffe", "kaffee zu trinken"]', '["dricka kaffe", "drinking coffee", "dricka kaffe", "kaffee zu trinken"]', '["kaffee zu trinken", "drinking coffee", "dricka kaffe", "kaffee zu trinken"]', 'intermediate', true, 18),
(1, 'Arkadaşlarımı davet edip parti yapacağım.', 'I''ll invite my friends and have a party.', 'Jag ska bjuda in mina vänner och ha en fest.', 'Ich werde meine Freunde einladen und eine Party machen.', '["parti yapacağım", "have a party", "ha en fest", "party machen"]', '["have a party", "have a party", "ha en fest", "party machen"]', '["ha en fest", "have a party", "ha en fest", "party machen"]', '["party machen", "have a party", "ha en fest", "party machen"]', 'intermediate', true, 19),
(1, 'Müzik dinlerken çalışmayı tercih ederim.', 'I prefer to work while listening to music.', 'Jag föredrar att arbeta medan jag lyssnar på musik.', 'Ich bevorzuge es, zu arbeiten, während ich Musik höre.', '["müzik dinlerken", "listening to music", "lyssnar på musik", "musik höre"]', '["listening to music", "listening to music", "lyssnar på musik", "musik höre"]', '["lyssnar på musik", "listening to music", "lyssnar på musik", "musik höre"]', '["musik höre", "listening to music", "lyssnar på musik", "musik höre"]', 'intermediate', true, 20);
